#include <grpcpp/support/channel_arguments.h>

int main() {
  grpc::ChannelArguments args;

  // Set message size limits
  args.SetMaxReceiveMessageSize(50 * 1024 * 1024);  // 50 MB
  args.SetMaxSendMessageSize(50 * 1024 * 1024);

  // Enable GZIP compression
  args.SetCompressionAlgorithm(GRPC_COMPRESS_GZIP);

  // Set load balancing policy
  args.SetLoadBalancingPolicyName("round_robin");

  // Set user agent
  args.SetUserAgentPrefix("MyService/1.0");

  // Create credentials and channel
  auto creds = grpc::InsecureChannelCredentials();
  auto channel = grpc::CreateCustomChannel("localhost:50051", creds, args);

  auto stub = MyService::NewStub(channel);
  // ... make RPC calls with custom configuration ...

  return 0;
}
